import React, { useState } from 'react';
import api from '../services/api';

function FriendList({ friends, onFriendChange }) {
  const [newFriendName, setNewFriendName] = useState('');
  const [loading, setLoading] = useState(false);

  const addFriend = async (e) => {
    e.preventDefault();
    if (!newFriendName.trim()) {
      alert('Please enter a name');
      return;
    }

    setLoading(true);
    try {
      await api.addFriend(newFriendName);
      setNewFriendName('');
      onFriendChange();
    } catch (error) {
      console.error('Error adding friend:', error);
      alert('Error adding friend');
    } finally {
      setLoading(false);
    }
  };

  const deleteFriend = async (id, name) => {
    if (window.confirm(`Are you sure you want to delete ${name}?`)) {
      try {
        await api.deleteFriend(id);
        onFriendChange();
      } catch (error) {
        console.error('Error deleting friend:', error);
        alert('Error deleting friend');
      }
    }
  };

  return (
    <div>
      <h2>Friends</h2>
      
      <div className="card">
        <h3>Add New Friend</h3>
        <form onSubmit={addFriend}>
          <input
            type="text"
            placeholder="Friend's name"
            value={newFriendName}
            onChange={(e) => setNewFriendName(e.target.value)}
            style={{ marginRight: '10px', width: '200px' }}
          />
          <button type="submit" disabled={loading}>
            {loading ? 'Adding...' : 'Add Friend'}
          </button>
        </form>
      </div>

      <div className="friend-list">
        <h3>Your Friends ({friends.length})</h3>
        {friends.length === 0 ? (
          <p>No friends added yet. Add your first friend above!</p>
        ) : (
          friends.map(friend => (
            <div key={friend.id} className="friend-item">
              <span>{friend.name}</span>
              <button 
                onClick={() => deleteFriend(friend.id, friend.name)}
                style={{ background: '#ef4444', padding: '5px 10px' }}
              >
                Delete
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

export default FriendList;
